(function(){"use strict";function wrapTables(){document.querySelectorAll("table").forEach(function(t){t.classList.contains("table")||t.classList.add("table");if(!t.parentElement||!t.parentElement.classList.contains("table-responsive")){var w=document.createElement("div");w.className="table-responsive";t.parentNode.insertBefore(w,t);w.appendChild(t)}})}function wrapVideos(){document.querySelectorAll('iframe[src*="youtube.com"],iframe[src*="youtube-nocookie.com"],iframe[src*="vimeo.com"]').forEach(function(f){f.classList.contains("embed-responsive-item")||f.classList.add("embed-responsive-item");if(!f.parentElement||!f.parentElement.classList.contains("embed-responsive")){var w=document.createElement("div");w.className="embed-responsive embed-responsive-16by9";f.parentNode.insertBefore(w,f);w.appendChild(f)}})}function initNavbarScroll(){var MQL=1170,CATALOG_OFFSET=41,navbar=document.querySelector(".navbar-custom");if(!navbar)return;var introContainer=document.querySelector(".intro-header .container"),headerHeight=navbar.offsetHeight,bannerHeight=introContainer?introContainer.offsetHeight:0,previousTop=0,ticking=false,catalogInitialized=false;window.addEventListener("scroll",function(){if(!ticking){window.requestAnimationFrame(function(){var currentTop=window.scrollY||window.pageYOffset;if(window.innerWidth>MQL){var catalog=document.querySelector(".side-catalog");if(currentTop<previousTop){if(currentTop>0&&navbar.classList.contains("is-fixed")){navbar.classList.add("is-visible")}else{navbar.classList.remove("is-visible","is-fixed")}}else{navbar.classList.remove("is-visible");if(currentTop>headerHeight&&!navbar.classList.contains("is-fixed")){navbar.classList.add("is-fixed")}}if(catalog){if(!catalogInitialized){catalog.style.display="";catalogInitialized=true}if(currentTop>bannerHeight+CATALOG_OFFSET){catalog.classList.add("fixed")}else{catalog.classList.remove("fixed")}}}else{navbar.classList.remove("is-visible","is-fixed")}previousTop=currentTop;ticking=false});ticking=true}})}document.addEventListener("DOMContentLoaded",function(){wrapTables();wrapVideos();initNavbarScroll()})})();
